def _select_tip_with_weights(self):
    """Select a tip key from TIPS using self.tip_weights, biasing the draw via cumulative distribution.

    Nonpositive or missing weights are treated as documented; if the total weight is zero, falls back to a
    uniform draw so a fixed seed still yields deterministic (though unweighted) selection.
    """
    tip_keys = list(TIPS.keys())
    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in tip_keys]
    total_weight = sum(weights)

    if total_weight <= 0:
        return self.rng.choice(tip_keys)

    threshold = self.rng.random() * total_weight
    cumulative = 0.0
    for key, weight in zip(tip_keys, weights):
        cumulative += weight
        if threshold < cumulative:
            return key
    return tip_keys[-1]

